package com.multilanglearner.data.network

import android.util.Log
import com.multilanglearner.domain.model.AIConfig
import com.multilanglearner.domain.model.WordTimestamp
import kotlinx.serialization.Serializable
import kotlinx.serialization.json.*
import okhttp3.*
import okhttp3.MediaType.Companion.toMediaType
import okhttp3.RequestBody.Companion.asRequestBody
import okhttp3.RequestBody.Companion.toRequestBody
import java.io.File
import java.util.concurrent.TimeUnit
import javax.inject.Inject
import javax.inject.Singleton

@Serializable
data class WhisperResult(
    val success: Boolean,
    val text: String = "",
    val words: List<WordTimestamp> = emptyList(),
    val detectedLang: String = "",
    val error: String = ""
)

@Singleton
class WhisperService @Inject constructor() {
    private val client = OkHttpClient.Builder()
        .connectTimeout(15, TimeUnit.SECONDS)  // 减少连接超时，加快重试
        .readTimeout(600, TimeUnit.SECONDS)    // 增加读取超时，支持长音频
        .writeTimeout(120, TimeUnit.SECONDS)   // 增加写入超时
        .retryOnConnectionFailure(true)        // 启用自动重试
        .build()

    private val json = Json { ignoreUnknownKeys = true }

    // Groq API 文件大小限制（增加到 100MB，Groq 实际支持更大）
    private val MAX_FILE_SIZE = 100 * 1024 * 1024L
    private val MIN_FILE_SIZE = 1024L // 最小 1KB，避免空文件或太小的文件

    // 最大重试次数
    private val MAX_RETRIES = 3

    /**
     * Transcribe audio via Groq Whisper API
     * 优先使用 groqApiKey，其次使用 provider 为 groq 时的 apiKey
     * 添加自动重试机制
     */
    suspend fun transcribeGroq(audioFile: File, config: AIConfig, lang: String? = null): WhisperResult? {
        // 自动重试逻辑
        var lastError: Exception? = null
        repeat(MAX_RETRIES) { attempt ->
            if (attempt > 0) {
                Log.d("WhisperService", "Retry $attempt/$MAX_RETRIES")
                kotlinx.coroutines.delay(2000L * attempt) // 递增延迟
            }

            val result = transcribeGroqInternal(audioFile, config, lang)
            if (result?.success == true) {
                return result
            }
            lastError = Exception(result?.error ?: "Unknown error")
        }

        // 所有重试都失败
        return WhisperResult(
            success = false,
            error = "❌ 转录失败（已重试 $MAX_RETRIES 次）\n\n${lastError?.message ?: "未知错误"}\n\n建议：检查网络连接和 API Key 配置"
        )
    }

    /**
     * 内部转录实现
     */
    private suspend fun transcribeGroqInternal(audioFile: File, config: AIConfig, lang: String? = null): WhisperResult? {
        // 获取 Groq API Key：优先使用专门的 groqApiKey，其次检查 provider 是否为 groq
        val apiKey = config.groqApiKey.takeIf { it.isNotBlank() }
            ?: (config.apiKey.takeIf { config.provider == "groq" && it.isNotBlank() })
            ?: return WhisperResult(success = false, error = "❌ 未配置 Groq API Key\n\n请前往「AI 设置」配置 Groq API Key。\n获取 API Key：https://console.groq.com/keys")

        val whisperModel = config.whisperModel.ifBlank { "whisper-large-v3-turbo" }

        // 检查文件大小
        val fileSize = audioFile.length()
        Log.d("WhisperService", "File size: $fileSize bytes, max: $MAX_FILE_SIZE")

        // 检查最小文件大小
        if (fileSize < MIN_FILE_SIZE) {
            Log.e("WhisperService", "File too small: $fileSize bytes (min: $MIN_FILE_SIZE)")
            return WhisperResult(
                success = false,
                error = "❌ 视频文件过小\n\n文件大小: ${fileSize / 1024} KB\n最小要求: 1 KB\n\n建议：请使用包含音频内容的有效视频文件"
            )
        }

        if (fileSize > MAX_FILE_SIZE) {
            val sizeMB = String.format("%.2f", fileSize / 1024.0 / 1024.0)
            val maxMB = String.format("%.2f", MAX_FILE_SIZE / 1024.0 / 1024.0)
            Log.e("WhisperService", "File too large: $sizeMB MB (max: $maxMB MB)")
            return WhisperResult(
                success = false,
                error = "❌ 视频文件过大\n\n文件大小: $sizeMB MB\nGroq 限制: $maxMB MB\n\n建议解决方案：\n1. 使用较短的视频片段\n2. 在电脑上用 ffmpeg 压缩视频\n3. 在电脑上使用 yt-dlp 只下载音频"
            )
        }

        Log.d("WhisperService", "Starting transcription with Groq Whisper: model=$whisperModel, file=${audioFile.name}, size=$fileSize")

        val bodyBuilder = MultipartBody.Builder().setType(MultipartBody.FORM)
            .addFormDataPart("file", audioFile.name, audioFile.asRequestBody("application/octet-stream".toMediaType()))
            .addFormDataPart("model", whisperModel)
            .addFormDataPart("response_format", "verbose_json")
            .addFormDataPart("timestamp_granularities[]", "word")
            .addFormDataPart("timestamp_granularities[]", "segment")
            .addFormDataPart("temperature", "0")
            .addFormDataPart("prompt", "Transcribe accurately with proper punctuation and capitalization.")

        lang?.let { bodyBuilder.addFormDataPart("language", it) }

        val request = Request.Builder()
            .url("https://api.groq.com/openai/v1/audio/transcriptions")
            .addHeader("Authorization", "Bearer $apiKey")
            .post(bodyBuilder.build())
            .build()

        return try {
            Log.d("WhisperService", "Sending request to Groq API...")
            val response = client.newCall(request).execute()

            Log.d("WhisperService", "Response code: ${response.code}")

            if (response.code != 200) {
                val errorBody = response.body?.string() ?: "Unknown error"
                Log.e("WhisperService", "API error: $errorBody")

                // 解析错误信息
                val errorMsg = try {
                    val errorJson = json.parseToJsonElement(errorBody).jsonObject
                    val errObj = errorJson["error"]?.jsonObject
                    val errMsg = errObj?.get("message")?.jsonPrimitive?.contentOrNull
                    val errType = errObj?.get("type")?.jsonPrimitive?.contentOrNull
                    val errCode = errObj?.get("code")?.jsonPrimitive?.contentOrNull

                    when {
                        errMsg?.contains("invalid_api_key", ignoreCase = true) == true ||
                        errMsg?.contains("Unauthorized", ignoreCase = true) == true ||
                        response.code == 401 ->
                            "❌ API Key 无效\n\n请检查 Groq API Key 是否正确配置\n\n获取 API Key：https://console.groq.com/keys"
                        errMsg?.contains("quota", ignoreCase = true) == true ||
                        errMsg?.contains("limit", ignoreCase = true) == true ||
                        errMsg?.contains("rate_limit", ignoreCase = true) == true ||
                        response.code == 429 ->
                            "❌ API 配额已用完\n\nGroq API 使用次数已达限制\n\n建议：\n1. 等待配额重置\n2. 更换 API Key\n3. 升级 Groq 账户"
                        errMsg?.contains("forbidden", ignoreCase = true) == true ||
                        errMsg?.contains("banned", ignoreCase = true) == true ||
                        response.code == 403 ->
                            "❌ 转录被禁止\n\n${errMsg ?: "访问被限制"}\n\n可能原因：\n1. API Key 被禁用\n2. 账户存在违规行为\n3. 内容不符合使用条款"
                        else -> "❌ 转录失败 ($response.code)\n\n${errMsg ?: errorBody}"
                    }
                } catch (e: Exception) {
                    "❌ 转录失败\n\n${errorBody.take(200)}"
                }

                return WhisperResult(success = false, error = errorMsg)
            }

            val body = response.body?.string() ?: return WhisperResult(success = false, error = "空响应")
            Log.d("WhisperService", "Response length: ${body.length}")
            Log.d("WhisperService", "Response body preview: ${body.take(500)}")

            // 检查响应是否为有效的 JSON
            if (!body.trim().startsWith("{") && !body.trim().startsWith("[")) {
                Log.e("WhisperService", "Response is not valid JSON: ${body.take(200)}")
                return WhisperResult(
                    success = false,
                    error = "❌ API 返回格式错误\n\nGroq API 返回了非 JSON 格式的响应。\n\n响应内容：\n${body.take(500)}"
                )
            }

            try {
                val jsonObj = json.parseToJsonElement(body).jsonObject
                val text = jsonObj["text"]?.jsonPrimitive?.contentOrNull ?: ""
                val detectedLang = jsonObj["language"]?.jsonPrimitive?.contentOrNull ?: ""

                Log.d("WhisperService", "Transcribed text length: ${text.length}, detected language: $detectedLang")

                val words = jsonObj["words"]?.jsonArray?.map { w ->
                    val obj = w.jsonObject
                    WordTimestamp(
                        w = obj["word"]?.jsonPrimitive?.contentOrNull ?: "",
                        s = (obj["start"]?.jsonPrimitive?.doubleOrNull ?: 0.0),
                        e = (obj["end"]?.jsonPrimitive?.doubleOrNull ?: 0.0)
                    )
                } ?: emptyList()

                Log.d("WhisperService", "Word timestamps count: ${words.size}")

                WhisperResult(
                    success = true,
                    text = text,
                    words = words,
                    detectedLang = detectedLang
                )
            } catch (e: Exception) {
                Log.e("WhisperService", "JSON parsing error", e)
                Log.e("WhisperService", "Response body: $body")
                WhisperResult(
                    success = false,
                    error = "❌ 响应解析失败\n\nGroq API 返回了无法解析的响应。\n\n错误: ${e.message}\n\n响应内容：\n${body.take(500)}"
                )
            }
        } catch (e: Exception) {
            Log.e("WhisperService", "Transcription error", e)
            val errorMsg = when {
                e.message?.contains("timeout", ignoreCase = true) == true ->
                    "❌ 请求超时\n\n网络连接超时，请检查网络连接后重试。"
                e.message?.contains("Unable to resolve host", ignoreCase = true) == true ||
                e.message?.contains("UnknownHost", ignoreCase = true) == true ->
                    "❌ 网络连接失败\n\n无法连接到 Groq API 服务器，请检查网络连接。"
                else -> "❌ 转录失败\n\n${e.message ?: "未知错误"}\n\n请检查网络连接和 API Key 配置后重试。"
            }
            WhisperResult(success = false, error = errorMsg)
        }
    }
}

package com.multilanglearner.ui.home

import android.content.BroadcastReceiver
import android.content.Context
import android.content.Intent
import android.content.IntentFilter
import android.net.Uri
import androidx.activity.compose.rememberLauncherForActivityResult
import androidx.activity.result.contract.ActivityResultContracts
import androidx.compose.foundation.ExperimentalFoundationApi
import androidx.compose.foundation.combinedClickable
import androidx.compose.foundation.layout.Box
import androidx.compose.foundation.layout.offset
import androidx.compose.foundation.layout.padding
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.lazy.LazyColumn
import androidx.compose.foundation.lazy.items
import androidx.compose.foundation.shape.CircleShape
import androidx.compose.foundation.shape.RoundedCornerShape
import androidx.compose.material.icons.Icons
import androidx.compose.material.icons.filled.*
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.platform.LocalClipboardManager
import androidx.compose.ui.platform.LocalContext
import androidx.compose.ui.text.style.TextOverflow
import androidx.compose.ui.unit.dp
import androidx.hilt.navigation.compose.hiltViewModel
import com.multilanglearner.data.db.entity.VideoEntity
import com.multilanglearner.domain.model.LANGUAGES
import com.multilanglearner.service.TranscriptionService
import java.io.File

@OptIn(ExperimentalMaterial3Api::class, ExperimentalFoundationApi::class)
@Composable
fun HomeScreen(
    onNavigateToPlayer: (String, String?) -> Unit,
    onNavigateToVocabulary: () -> Unit,
    onNavigateToRegulation: () -> Unit,
    viewModel: HomeViewModel = hiltViewModel()
) {
    val uiState by viewModel.uiState.collectAsState()
    val clipboardManager = LocalClipboardManager.current
    val context = LocalContext.current
    var showAISettings by remember { mutableStateOf(false) }
    var showAssistant by remember { mutableStateOf(false) }
    var showThemeDialog by remember { mutableStateOf(false) }
    var showVideoDownloadSettings by remember { mutableStateOf(false) }

    // 视频列表类型切换：已下载 / 已转录
    var videoListType by remember { mutableStateOf(0) } // 0 = 已下载, 1 = 已转录

    // 转录服务广播接收器
    val transcriptionQueueReceiver = remember {
        object : BroadcastReceiver() {
            override fun onReceive(context: Context?, intent: Intent?) {
                when (intent?.action) {
                    TranscriptionService.ACTION_PROGRESS -> {
                        val message = intent.getStringExtra(TranscriptionService.EXTRA_MESSAGE) ?: ""
                        val progress = intent.getIntExtra(TranscriptionService.EXTRA_PROGRESS, 0)
                        // 从消息中提取当前转录的视频名称
                        val currentVideo = message.substringBefore(")").trim()
                        viewModel.updateTranscriptionQueue(currentVideo, uiState.transcriptionQueue, progress, message)
                    }
                    TranscriptionService.ACTION_QUEUE_UPDATE -> {
                        val queueArray = intent.getStringArrayExtra(TranscriptionService.EXTRA_QUEUE_LIST)
                        val queueList = queueArray?.toList() ?: emptyList()
                        viewModel.updateTranscriptionQueue(uiState.transcribingVideo, queueList, uiState.transcriptionProgress, uiState.transcriptionMessage)
                    }
                    TranscriptionService.ACTION_COMPLETED -> {
                        viewModel.transcriptionCompleted()
                    }
                }
            }
        }
    }

    // 注册和注销转录广播接收器
    DisposableEffect(Unit) {
        val progressFilter = IntentFilter(TranscriptionService.ACTION_PROGRESS)
        val queueFilter = IntentFilter(TranscriptionService.ACTION_QUEUE_UPDATE)
        val completedFilter = IntentFilter(TranscriptionService.ACTION_COMPLETED)
        context.registerReceiver(transcriptionQueueReceiver, progressFilter)
        context.registerReceiver(transcriptionQueueReceiver, queueFilter)
        context.registerReceiver(transcriptionQueueReceiver, completedFilter)

        onDispose {
            context.unregisterReceiver(transcriptionQueueReceiver)
        }
    }

    // 确认对话框状态
    var showDeleteConfirm by remember { mutableStateOf(false) }
    var showLocationConfirm by remember { mutableStateOf(false) }
    var showShareConfirm by remember { mutableStateOf(false) }
    var selectedVideo by remember { mutableStateOf<VideoEntity?>(null) }

    // Video file picker launcher
    val videoPickerLauncher = rememberLauncherForActivityResult(
        contract = ActivityResultContracts.GetContent()
    ) { uri: Uri? ->
        uri?.let {
            viewModel.importVideo(context, it) { path, sub ->
                onNavigateToPlayer(path, sub)
            }
        }
    }

    Scaffold(
        topBar = {
            TopAppBar(
                title = {
                    Column {
                        Text("多语言视频学习", style = MaterialTheme.typography.titleLarge)
                        Text("视频字幕 · 点词翻译 · AI释义 · 听写训练",
                            style = MaterialTheme.typography.bodySmall,
                            color = MaterialTheme.colorScheme.onSurfaceVariant)
                    }
                },
                actions = {
                    // AI设置按钮
                    IconButton(onClick = { showAISettings = true }) {
                        Icon(Icons.Default.SmartDisplay, "AI设置")
                    }
                    IconButton(onClick = { showVideoDownloadSettings = true }) {
                        Icon(Icons.Default.CloudDownload, "下载设置")
                    }
                    IconButton(onClick = { showThemeDialog = true }) {
                        Icon(Icons.Default.Palette, "主题")
                    }
                }
            )
        }
    ) { padding ->
        Column(
            modifier = Modifier.fillMaxSize().padding(padding).padding(horizontal = 16.dp)
        ) {
            // URL Input Row
            Card(modifier = Modifier.fillMaxWidth()) {
                Column(modifier = Modifier.padding(16.dp)) {
                    Row(verticalAlignment = Alignment.CenterVertically) {
                        OutlinedTextField(
                            value = uiState.url,
                            onValueChange = viewModel::setUrl,
                            placeholder = { Text("粘贴 YouTube/B站/抖音 视频链接...") },
                            modifier = Modifier.weight(1f),
                            singleLine = true,
                            trailingIcon = {
                                if (uiState.url.isNotEmpty()) {
                                    IconButton(onClick = { viewModel.setUrl("") }) {
                                        Icon(Icons.Default.Clear, "清除")
                                    }
                                }
                            }
                        )
                        Spacer(Modifier.width(8.dp))
                        IconButton(onClick = {
                            clipboardManager.getText()?.text?.let { text ->
                                val urlMatch = Regex("https?://[^\\s\"'<>]+").find(text)
                                viewModel.setUrl(urlMatch?.value ?: text.trim())
                            }
                        }) { Icon(Icons.Default.ContentPaste, "粘贴") }
                    }

                    Spacer(Modifier.height(8.dp))

                    // Language selector + buttons
                    Row(verticalAlignment = Alignment.CenterVertically) {
                        var langExpanded by remember { mutableStateOf(false) }
                        ExposedDropdownMenuBox(expanded = langExpanded, onExpandedChange = { langExpanded = it }) {
                            OutlinedTextField(
                                value = LANGUAGES.find { it.code == uiState.selectedLang }?.name ?: "英语",
                                onValueChange = {},
                                readOnly = true,
                                modifier = Modifier.menuAnchor().width(100.dp),
                                trailingIcon = { ExposedDropdownMenuDefaults.TrailingIcon(langExpanded) },
                                textStyle = MaterialTheme.typography.bodySmall
                            )
                            ExposedDropdownMenu(expanded = langExpanded, onDismissRequest = { langExpanded = false }) {
                                LANGUAGES.forEach { lang ->
                                    DropdownMenuItem(
                                        text = { Text(lang.name) },
                                        onClick = { viewModel.setLang(lang.code); langExpanded = false }
                                    )
                                }
                            }
                        }

                        Spacer(Modifier.width(8.dp))
                        Button(
                            onClick = { viewModel.downloadVideo { path, sub -> onNavigateToPlayer(path, sub) } },
                            enabled = uiState.url.isNotBlank() && uiState.activeDownloads.size < 3
                        ) {
                            if (uiState.isProcessing) {
                                CircularProgressIndicator(
                                    modifier = Modifier.size(16.dp),
                                    strokeWidth = 2.dp,
                                    color = MaterialTheme.colorScheme.onPrimary
                                )
                                Spacer(Modifier.width(4.dp))
                            }
                            Text(if (uiState.isProcessing) "处理中" else "下载")
                        }

                        Spacer(Modifier.width(4.dp))
                        OutlinedButton(onClick = { videoPickerLauncher.launch("video/*") }) {
                            Icon(Icons.Default.FolderOpen, null, Modifier.size(16.dp))
                            Spacer(Modifier.width(4.dp))
                            Text("导入")
                        }
                    }

                    // 下载进度卡片 - 显示所有正在下载的任务
                    if (uiState.activeDownloads.isNotEmpty()) {
                        Spacer(Modifier.height(12.dp))
                        // 过滤出需要显示的任务
                        val downloadingTasks = uiState.activeDownloads.values.filter { task ->
                            task.status == DownloadStatus.DOWNLOADING ||
                            task.status == DownloadStatus.FETCHING_INFO ||
                            task.status == DownloadStatus.WAITING_FOR_AUTH
                        }
                        downloadingTasks.forEach { task ->
                            DownloadProgressCard(
                                task = task,
                                onCancel = { viewModel.cancelDownload(task.id) },
                                formatFileSize = { viewModel.formatFileSize(it) },
                                formatSpeed = { viewModel.formatSpeed(it) },
                                formatRemainingTime = { viewModel.formatRemainingTime(it) },
                                getStatusText = { viewModel.getStatusText(it) }
                            )
                            Spacer(Modifier.height(8.dp))
                        }
                    }

                    // 下载队列提示
                    if (uiState.downloadQueue.isNotEmpty()) {
                        Spacer(Modifier.height(8.dp))
                        Surface(
                            modifier = Modifier.fillMaxWidth(),
                            color = MaterialTheme.colorScheme.secondaryContainer,
                            shape = RoundedCornerShape(8.dp)
                        ) {
                            Row(
                                modifier = Modifier.padding(12.dp),
                                verticalAlignment = Alignment.CenterVertically
                            ) {
                                Icon(
                                    Icons.Default.Info,
                                    contentDescription = null,
                                    tint = MaterialTheme.colorScheme.onSecondaryContainer,
                                    modifier = Modifier.size(20.dp)
                                )
                                Spacer(Modifier.width(8.dp))
                                Text(
                                    "队列中有 ${uiState.downloadQueue.size} 个任务等待下载",
                                    style = MaterialTheme.typography.bodySmall,
                                    color = MaterialTheme.colorScheme.onSecondaryContainer
                                )
                            }
                        }
                    }
                }
            }

            Spacer(Modifier.height(8.dp))

            // 转录进度卡片（如果有视频正在转录）
            uiState.transcribingVideo?.let { currentVideo ->
                TranscriptionProgressCard(
                    currentVideo = currentVideo,
                    queueList = uiState.transcriptionQueue,
                    progress = uiState.transcriptionProgress,
                    message = uiState.transcriptionMessage
                )
                Spacer(Modifier.height(8.dp))
            }

            // Function buttons row
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                AssistChip(onClick = onNavigateToVocabulary, label = { Text("词书") },
                    leadingIcon = { Icon(Icons.Default.Book, null, Modifier.size(16.dp)) })
                AssistChip(onClick = { showAssistant = true }, label = { Text("助手") },
                    leadingIcon = { Icon(Icons.Default.Mic, null, Modifier.size(16.dp)) })
                AssistChip(onClick = onNavigateToRegulation, label = { Text("法规") },
                    leadingIcon = { Icon(Icons.Default.Gavel, null, Modifier.size(16.dp)) })
                Spacer(Modifier.weight(1f))
                AssistChip(onClick = onNavigateToVocabulary, label = { Text("收藏") },
                    leadingIcon = { Icon(Icons.Default.Favorite, null, Modifier.size(16.dp), tint = Color(0xFFF44336)) })
            }

            Spacer(Modifier.height(12.dp))

            // 视频列表切换：已下载 / 已转录
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                Text(
                    when (videoListType) {
                        0 -> "已下载视频"
                        1 -> "已转录视频"
                        else -> "视频列表"
                    },
                    style = MaterialTheme.typography.titleMedium
                )
                // 切换按钮
                Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                    FilterChip(
                        selected = videoListType == 0,
                        onClick = { videoListType = 0 },
                        label = { Text("已下载") },
                        leadingIcon = { if (videoListType == 0) Icon(Icons.Default.Check, null, Modifier.size(16.dp)) else null },
                        trailingIcon = { Text(uiState.videos.count { it.vttPath == null || !File(it.vttPath).exists() }.toString()) }
                    )
                    FilterChip(
                        selected = videoListType == 1,
                        onClick = { videoListType = 1 },
                        label = { Text("已转录") },
                        leadingIcon = { if (videoListType == 1) Icon(Icons.Default.Check, null, Modifier.size(16.dp)) else null },
                        trailingIcon = { Text(uiState.videos.count { it.vttPath != null && File(it.vttPath).exists() }.toString()) }
                    )
                }
            }
            Spacer(Modifier.height(8.dp))

            // 过滤视频列表 - 两个列表不重叠
            val filteredVideos = when (videoListType) {
                0 -> uiState.videos.filter { it.vttPath == null || !File(it.vttPath).exists() }  // 已下载但未转录
                1 -> uiState.videos.filter { it.vttPath != null && File(it.vttPath).exists() }  // 已转录
                else -> uiState.videos
            }

            if (filteredVideos.isEmpty()) {
                Box(Modifier.fillMaxWidth().padding(32.dp), contentAlignment = Alignment.Center) {
                    Text(
                        when (videoListType) {
                            0 -> "暂无下载视频\n点击上方「下载」添加视频"
                            1 -> "暂无已转录视频\n进入播放器点击「重新转录」"
                            else -> "暂无视频"
